SELECT CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= :param_1) THEN DATEFROMPARTS(YEAR(lk.lk_referral_date), MONTH(lk.lk_referral_date), 1) ELSE NULL END AS event_month, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= :param_1 AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) > :param_2) THEN :param_3 WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= :param_1 AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) < :param_4) THEN :param_5 WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= :param_1) THEN DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) ELSE NULL END AS lag_day, CAST(demo_health.dbo.episodes.loaded_at AS DATE) AS load_epoch_day, CAST(NULL AS VARCHAR(max)) AS batch_id, CAST(NULL AS VARCHAR(max)) AS alt_value, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= :param_1) THEN :param_6 ELSE :param_7 END AS is_eligible, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NULL) THEN :param_8 ELSE :param_9 END AS is_null_event_time, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NULL) THEN :param_10 ELSE :param_11 END AS is_null_load_time_only, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= :param_12 AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) < :param_13) THEN :param_14 ELSE :param_15 END AS is_negative_clipped, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) < :param_16) THEN :param_17 ELSE :param_18 END AS is_negative_lag_excluded, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= :param_1 AND DATEDIFF(day, lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) > :param_19) THEN :param_20 ELSE :param_21 END AS is_overflow, CASE WHEN (lk.lk_matched IS NULL) THEN :param_22 ELSE :param_23 END AS is_join_unmatched, CASE WHEN (lk.lk_matched IS NULL OR lk.lk_rn = :lk_rn_1) THEN :param_24 ELSE :param_25 END AS is_base_row, CASE WHEN (lk.lk_rn = :lk_rn_2 AND lk.lk_dup > :lk_dup_1) THEN :param_26 ELSE :param_27 END AS is_ambiguous_base, CAST(:param_28 AS INTEGER) AS is_compare_mismatch, lk.lk_dup AS lookup_dup, CAST(NULL AS VARCHAR(max)) AS key_hash, demo_health.dbo.episodes.loaded_at AS load_time  INTO #mp_probe 
FROM demo_health.dbo.episodes LEFT OUTER JOIN (SELECT demo_health.dbo.referrals.id AS lk_id, demo_health.dbo.referrals.referral_date AS lk_referral_date, demo_health.dbo.referrals.site AS lk_site, :param_29 AS lk_matched, count(*) OVER (PARTITION BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site) AS lk_dup, row_number() OVER (PARTITION BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site ORDER BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site) AS lk_rn 
FROM demo_health.dbo.referrals) AS lk ON demo_health.dbo.episodes.referral_id = lk.lk_id AND demo_health.dbo.episodes.site_code = lk.lk_site 
WHERE demo_health.dbo.episodes.loaded_at <= :as_of OR demo_health.dbo.episodes.loaded_at IS NULL
